<script>
    function SafeGetValue(obj, path, defaultValue = "N/A") {
        let keys = Array.isArray(path) ? path : path.split('.');
        let current = obj;
        for (let i = 0; i < keys.length; i++) {
            if (current === undefined || current === null || typeof current !== 'object' || !current.hasOwnProperty(keys[i])) {
                return defaultValue;
            }
            current = current[keys[i]];
        }
        if (current === undefined || current === null) {
            return defaultValue;
        }
        if (Array.isArray(current)) {
            if (current.length > 0) {
                 const actualValue = current;
                 if (typeof actualValue === 'boolean') {
                     return actualValue;
                 }
                 return String(actualValue);
            } else {
                 return defaultValue;
            }
        }
        if (typeof current === 'boolean') {
            return current;
        }
        return String(current);
    }

    function updateProgressBar(barId, valueMainId, valueDescId, rawValue, min, max, color) {
        const progressBar = document.getElementById(barId);
        const valueMainDisplay = document.getElementById(valueMainId);
        const valueDescDisplay = document.getElementById(valueDescId);
        if (!valueMainDisplay) return;
        let displayString = SafeGetValue({ temp: rawValue }, 'temp', String(min));
        let numericValue = parseFloat(displayString);
        valueMainDisplay.innerText = displayString;
        if (valueDescDisplay) {
          if (numericValue <= 100) valueDescDisplay.innerText = '(观察试探)';
          else if (numericValue <= 200) valueDescDisplay.innerText = '(友达以上)';
          else if (numericValue <= 300) valueDescDisplay.innerText = '(心意萌动)';
          else valueDescDisplay.innerText = '(默契相伴)';
        }
        if (progressBar) {
            numericValue = Math.max(min, Math.min(max, numericValue));
            const range = max - min;
            const percentage = range === 0 ? (numericValue >= max ? 100 : 0) : ((numericValue - min) / range) * 100;
            progressBar.style.width = `${Math.max(0, Math.min(100, percentage))}%`;
            progressBar.style.backgroundColor = color ? color : 'var(--accent-highlight)';
        }
    }

    (async function initDisplay() {
        try {
            await waitGlobalInitialized('Mvu');
            let messageId = 'latest';
            if(typeof getCurrentMessageId === 'function') { messageId = getCurrentMessageId(); }
            const mvuData = Mvu.getMvuData({type: 'message', message_id: messageId});
            if (!mvuData || !mvuData.stat_data) {
                document.getElementById('status-card').innerHTML = `<p style='color:red; padding:10px;'>无法加载状态数据 (mvuData missing)</p>`;
                return;
            }
            const characterData = mvuData.stat_data;

            const year = SafeGetValue(characterData, '世界.年份.0', '----');
            const date = SafeGetValue(characterData, '世界.日期.0', '--月--日');
            const time = SafeGetValue(characterData, '世界.时间.0', '--:--');
            document.getElementById('world-datetime').innerText = `${year}年${date} ${time}`;

            const userFundsEl = document.getElementById('user-funds');
            if(userFundsEl) userFundsEl.innerText = '¥ ' + SafeGetValue(characterData, 'user.生活费.0', '0');

            const lingyueFundsEl = document.getElementById('lingyue-funds');
            if(lingyueFundsEl) lingyueFundsEl.innerText = '¥ ' + SafeGetValue(characterData, '凌月.生活费.0', '0');

            const affectionValue = SafeGetValue(characterData, '凌月.对user的好感度.0', '50');
            updateProgressBar(
                'lingyue-affection-bar',
                'lingyue-affection',
                'lingyue-affection-desc',
                `${affectionValue} / 400`,
                0,
                400,
                'var(--accent-highlight)'
            );

        } catch (error) {
            document.getElementById('status-card').innerHTML = `<p style='color:red; padding:10px;'>状态栏加载出错: ${error.message}</p>`;
        }
